// src/services/api.js
import { mockGroups } from '../mocks/groups';
import { login } from '../mocks/auth';

export const fetchGroups = () => {
    return new Promise((resolve) => {
        setTimeout(() => {
            resolve(mockGroups);
        }, 500);
    });
};
